[
    {
        "entity": "SARS-CoV-2",
        "behavior": "causes COVID-19",
        "context": "the respiratory illness responsible for the pandemic that began in late 2019",
        "priority": 1
    },
    {
        "entity": "SARS-CoV-2",
        "behavior": "spreads via aerosols and respiratory droplets",
        "context": "primarily between people through close contact, coughing, sneezing, or speaking",
        "priority": 1
    },
    {
        "entity": "SARS-CoV-2",
        "behavior": "enters human cells by binding to ACE2",
        "context": "utilizing a membrane protein that regulates the renin-angiotensin system",
        "priority": 1
    },
    {
        "entity": "SARS-CoV-2",
        "behavior": "is a positive-sense single-stranded RNA virus",
        "context": "biological classification of the contagious virus",
        "priority": 1
    },
    {
        "entity": "BANAL-52 bat coronavirus",
        "behavior": "is the closest known relative to SARS-CoV-2",
        "context": "suggesting the virus is of zoonotic origin and likely emerged from bats",
        "priority": 2
    },
    {
        "entity": "Nasal cavity",
        "behavior": "serves as the dominant initial site of infection",
        "context": "with subsequent aspiration-mediated virus-seeding into the lungs",
        "priority": 2
    },
    {
        "entity": "SARS-CoV-2",
        "behavior": "remains viable on surfaces",
        "context": "up to three days on plastic and stainless steel, but less on cardboard and copper",
        "priority": 2
    },
    {
        "entity": "Soap",
        "behavior": "inactivates the virus",
        "context": "by destabilizing its lipid bilayer",
        "priority": 2
    },
    {
        "entity": "Asymptomatic individuals",
        "behavior": "transmit the virus",
        "context": "though they are approximately 42% less likely to do so than symptomatic individuals",
        "priority": 2
    },
    {
        "entity": "Reinfection",
        "behavior": "occurs with variable severity",
        "context": "confirmed by whole-genome sequencing showing different clades in the same individual",
        "priority": 2
    },
    {
        "entity": "Pangolins",
        "behavior": "are likely not the intermediate host",
        "context": "viral samples are too distant (92% identical) and exhibit poor ACE2 binding",
        "priority": 2
    },
    {
        "entity": "Furin cleavage site",
        "behavior": "enhances virulence",
        "context": "a distinguishing feature incorporated into the SARS-CoV-2 spike protein, unique among its subgenus",
        "priority": 2
    },
    {
        "entity": "TMPRSS2",
        "behavior": "primes the initial spike protein",
        "context": "essential for viral entry by cutting open the spike protein to expose the fusion peptide",
        "priority": 2
    },
    {
        "entity": "Omicron variant",
        "behavior": "demonstrated significantly increased transmissibility",
        "context": "emerged in November 2021 and dominated circulating versions",
        "priority": 2
    },
    {
        "entity": "Nirmatrelvir/ritonavir",
        "behavior": "reduced the risk of hospitalization and death by 88%",
        "context": "an authorized treatment granted emergency use in late 2021",
        "priority": 2
    },
    {
        "entity": "Basic reproduction number (R0)",
        "behavior": "ranged from 2.39 to over 20",
        "context": "increasing from the wildtype virus to later variants like Omicron subvariants",
        "priority": 2
    },
    {
        "entity": "International Committee on Taxonomy of Viruses",
        "behavior": "adopted the official name SARS-CoV-2",
        "context": "on 11 February 2020",
        "priority": 3
    },
    {
        "entity": "Masitinib",
        "behavior": "inhibits SARS-CoV-2 main protease",
        "context": "shown in mice but not approved for human treatment",
        "priority": 3
    },
    {
        "entity": "ORF3d",
        "behavior": "provokes a strong immune response",
        "context": "a possible overlapping gene discovered in the genome in October 2020",
        "priority": 3
    },
    {
        "entity": "SARS-CoV-2 genome",
        "behavior": "has a bias against cytosine and guanine",
        "context": "containing highest composition of Uracil (32.2%)",
        "priority": 3
    }
]

[
    {
        "entity": "Ceres",
        "behavior": "is located",
        "context": "in the main asteroid belt between the orbits of Mars and Jupiter, classified as a dwarf planet and the largest object in the belt",
        "priority": 1
    },
    {
        "entity": "Giuseppe Piazzi",
        "behavior": "discovered",
        "context": "Ceres on January 1, 1801, at the Palermo Astronomical Observatory",
        "priority": 2
    },
    {
        "entity": "Ceres",
        "behavior": "possesses",
        "context": "a diameter of approximately 939 km and comprises about 40% of the asteroid belt's total mass",
        "priority": 2
    },
    {
        "entity": "Dawn spacecraft",
        "behavior": "revealed",
        "context": "Ceres's surface to be a mixture of water, ice, and hydrated minerals such as carbonates and clays during its orbital mission starting in 2015",
        "priority": 1
    },
    {
        "entity": "Gravity data",
        "behavior": "suggest",
        "context": "Ceres is partially differentiated into a muddy mantle/core and a less dense crust that is at most 30% ice by volume",
        "priority": 1
    },
    {
        "entity": "Cryovolcanoes",
        "behavior": "form",
        "context": "on the surface of Ceres, such as Ahuna Mons, driven by the flow of brines from the outer mantle",
        "priority": 1
    },
    {
        "entity": "Ceres",
        "behavior": "maintains",
        "context": "an extremely tenuous and transient atmosphere of water vapour vented from localized surface sources",
        "priority": 2
    },
    {
        "entity": "Bright spots",
        "behavior": "result from",
        "context": "the crystallization of brines containing sodium carbonate and ammonium salts that reached the surface, particularly in Occator Crater",
        "priority": 2
    },
    {
        "entity": "Ceres",
        "behavior": "lacks",
        "context": "the expected number of large craters, likely due to viscous relaxation of the crust slowly flattening out larger impacts",
        "priority": 2
    },
    {
        "entity": "Ammonium salts",
        "behavior": "support",
        "context": "the hypothesis that Ceres formed in the outer Solar System between Jupiter and Saturn and migrated inward, as ammonia is abundant there",
        "priority": 2
    },
    {
        "entity": "Organic compounds",
        "behavior": "were detected",
        "context": "in the Ernutet crater and other regions, indicating a chemistry favorable to organic evolution",
        "priority": 2
    },
    {
        "entity": "Ceres",
        "behavior": "has",
        "context": "an orbital period of 4.6 Earth years and a rotation period of approximately 9 hours and 4 minutes",
        "priority": 3
    },
    {
        "entity": "Permanently shadowed craters",
        "behavior": "act as",
        "context": "cold traps in the polar regions that accumulate water ice over time",
        "priority": 3
    },
    {
        "entity": "Ceres",
        "behavior": "is designated",
        "context": "as both an asteroid (1 Ceres) and a dwarf planet, following the 2006 IAU reclassification",
        "priority": 2
    },
    {
        "entity": "The surface",
        "behavior": "contains",
        "context": "carbon at approximately 20% by mass, which is five times higher than in carbonaceous chondrite meteorites",
        "priority": 3
    }
]

[
    {
        "entity": "Schizophrenia",
        "behavior": "is characterized by hallucinations, delusions, disorganized thinking, and flat affect",
        "context": "as a chronic mental disorder",
        "priority": 1
    },
    {
        "entity": "Schizophrenia prevalence",
        "behavior": "affects approximately 0.3% to 0.7% of people",
        "context": "globally during their lifetime",
        "priority": 1
    },
    {
        "entity": "Onset of schizophrenia",
        "behavior": "typically occurs between the late teens and early 30s",
        "context": "with males generally developing symptoms earlier than females",
        "priority": 2
    },
    {
        "entity": "Positive symptoms",
        "behavior": "include delusions, hallucinations, and disorganized thoughts",
        "context": "representing experiences not normally present",
        "priority": 1
    },
    {
        "entity": "Negative symptoms",
        "behavior": "manifest as deficits in emotional response and motivation",
        "context": "such as blunted affect, alogia, anhedonia, and avolition",
        "priority": 1
    },
    {
        "entity": "Cognitive deficits",
        "behavior": "affect memory, planning, and problem-solving in roughly 70% of patients",
        "context": "often appearing before the onset of psychosis",
        "priority": 2
    },
    {
        "entity": "Heritability",
        "behavior": "is estimated to be between 70% and 80%",
        "context": "suggesting a strong genetic component to the disorder",
        "priority": 1
    },
    {
        "entity": "Environmental risk factors",
        "behavior": "include urban upbringing, childhood adversity, cannabis use, and maternal infections",
        "context": "interacting with genetic predispositions",
        "priority": 2
    },
    {
        "entity": "Cannabis use",
        "behavior": "is associated with doubling the rate of schizophrenia",
        "context": "potentially triggering the disease in genetically at-risk individuals",
        "priority": 2
    },
    {
        "entity": "Diagnosis",
        "behavior": "is based on observed behavior and reported experiences over a specific duration",
        "context": "as there is no objective biological diagnostic test",
        "priority": 1
    },
    {
        "entity": "Antipsychotic medication",
        "behavior": "serves as the mainstay of treatment",
        "context": "often combined with psychosocial interventions",
        "priority": 1
    },
    {
        "entity": "Clozapine",
        "behavior": "shows the highest efficacy compared to other antipsychotics",
        "context": "in cases of treatment-resistant schizophrenia",
        "priority": 2
    },
    {
        "entity": "Dopamine hypothesis",
        "behavior": "attributes psychosis to the misfiring of dopaminergic neurons",
        "context": "explaining the mechanism of positive symptoms",
        "priority": 2
    },
    {
        "entity": "Life expectancy",
        "behavior": "is decreased by 20 to 28 years on average",
        "context": "due to higher suicide rates and physical health problems like cardiovascular disease",
        "priority": 1
    },
    {
        "entity": "Suicide rate",
        "behavior": "is significantly higher (about 5% overall) than the general population",
        "context": "particularly in the period following onset or first hospital admission",
        "priority": 2
    },
    {
        "entity": "Xanomeline/trospium chloride",
        "behavior": "was approved as the first cholinergic agonist treatment",
        "context": "by the US FDA in September 2024",
        "priority": 2
    },
    {
        "entity": "Eugen Bleuler",
        "behavior": "coined the term 'schizophrenia' in 1908",
        "context": "to describe the separation of mental functions",
        "priority": 3
    },
    {
        "entity": "Violence risk",
        "behavior": "is generally small and often associated with comorbid substance abuse",
        "context": "contrary to common public stereotypes",
        "priority": 2
    },
    {
        "entity": "Smoking",
        "behavior": "is prevalent in 80% to 90% of people with schizophrenia",
        "context": "possibly as a form of self-medication",
        "priority": 3
    }
]

[
    {
        "entity": "Trained immunity",
        "behavior": "is a long-term functional modification of chromatin leading to an altered response to a second unrelated challenge",
        "context": "in cells of the innate immune system",
        "priority": 1
    },
    {
        "entity": "Trained immunity",
        "behavior": "is mediated largely by epigenetic modifications",
        "context": "resulting in changes to the innate immune response",
        "priority": 1
    },
    {
        "entity": "Innate immune memory",
        "behavior": "lasts up to several months and is usually unspecific",
        "context": "in contrast to classical immunological memory which can last a lifetime and involves specific antibodies",
        "priority": 1
    },
    {
        "entity": "BCG vaccine",
        "behavior": "leads to a reduction in childhood mortality caused by unrelated infectious agents",
        "context": "as a primary example of trained immunity",
        "priority": 2
    },
    {
        "entity": "Trained immunity",
        "behavior": "possesses a transgenerational effect",
        "context": "observed in children of mothers vaccinated against BCG having lower mortality rates",
        "priority": 2
    },
    {
        "entity": "Myeloid cells",
        "behavior": "undergo functional reprogramming",
        "context": "which largely mediates trained immunity",
        "priority": 1
    },
    {
        "entity": "Fungal \u03b2-glucan",
        "behavior": "triggers changes in monocyte histone methylation",
        "context": "providing protection against reinfection or cross-protection against Staphylococcus aureus",
        "priority": 2
    },
    {
        "entity": "Monocytes and macrophages",
        "behavior": "undergo epigenetic modifications after ligation of pattern recognition receptors",
        "context": "preparing them for a heightened secondary response to the same or different pathogens",
        "priority": 1
    },
    {
        "entity": "Immune memory",
        "behavior": "is created at the level of progenitor cells",
        "context": "evidenced by the fact that monocytes are short-lived but the response lasts months",
        "priority": 1
    },
    {
        "entity": "Trained immunity",
        "behavior": "shifts macrophages toward a pro-inflammatory glycolytic M1 phenotype",
        "context": "via an Akt/mTor HIF1\u03b1 dependent pathway, moving away from the M2 phenotype",
        "priority": 2
    },
    {
        "entity": "NK cells",
        "behavior": "develop at least partially-specific clones with receptors against specific antigens",
        "context": "making their trained immunity resemble classic immunological memory",
        "priority": 1
    },
    {
        "entity": "Mihai Netea",
        "behavior": "coined the term 'trained immunity'",
        "context": "in 2011",
        "priority": 3
    },
    {
        "entity": "BRACE trial",
        "behavior": "is assessing if BCG vaccination can reduce the impact of COVID-19",
        "context": "in healthcare workers",
        "priority": 3
    },
    {
        "entity": "Epigenetic reprogramming",
        "behavior": "relies on mechanisms such as chromatin accessibility, DNA methylation, and histone modifications",
        "context": "leading to a stronger and rapid response to recurrent triggers",
        "priority": 1
    },
    {
        "entity": "Long non-coding RNAs (lncRNAs)",
        "behavior": "modulate gene expression by assigning H3K4me3 markers to the genome",
        "context": "playing a critical role in epigenetic reprogramming",
        "priority": 2
    },
    {
        "entity": "Cell metabolism",
        "behavior": "mediates trained immunity through increased aerobic glycolysis",
        "context": "specifically observed in monocytes trained with \u03b2-glucan",
        "priority": 1
    },
    {
        "entity": "Fumarate",
        "behavior": "leads to epigenetic reprogramming similar to \u03b2-glucan treatment",
        "context": "due to its accumulation caused by glutamine addition into the tricarboxylic acid cycle",
        "priority": 2
    }
]

[
    {
        "entity": "Diamond inclusions",
        "behavior": "preserve encapsulated materials intact",
        "context": "acting as a container under changing conditions from the mantle to the surface due to high strength and low reactivity",
        "priority": 1
    },
    {
        "entity": "Diamond inclusions",
        "behavior": "provide constraints on pressure, temperature, and age of formation",
        "context": "offering geological data beyond the lower pressure bound provided by the diamond itself",
        "priority": 1
    },
    {
        "entity": "Silicate inclusions",
        "behavior": "are classified into eclogite (E-type) and peridotite (P-type)",
        "context": "in lithospheric diamonds, depending on the mantle parental rocks",
        "priority": 1
    },
    {
        "entity": "Garnet inclusions",
        "behavior": "are distinguished into P-type and E-type based on chemical content",
        "context": "specifically using the ratio of chromium(III) oxide (Cr2O3) and calcium oxide (CaO)",
        "priority": 2
    },
    {
        "entity": "Seismic velocity",
        "behavior": "correlates with the nature of diamond inclusions (peridotitic or eclogitic)",
        "context": "at 150-km depth in the cratonic crust of the Kaapvaal-Zimbabwe craton",
        "priority": 3
    },
    {
        "entity": "Sub-lithospheric mineral inclusions",
        "behavior": "are difficult to classify",
        "context": "due to sample rarity, small grain size, and difficulties in recognizing original mineral assemblages",
        "priority": 3
    },
    {
        "entity": "Protogenetic inclusions",
        "behavior": "crystallized earlier than the diamond formation",
        "context": "providing information on conditions existing before the diamond encapsulated the pre-existing minerals",
        "priority": 2
    },
    {
        "entity": "Syngenetic inclusions",
        "behavior": "crystallized simultaneously with the diamond",
        "context": "often evidenced by the imposition of host diamond morphology on the trapped mineral",
        "priority": 2
    },
    {
        "entity": "Epigenetic inclusions",
        "behavior": "formed after the diamond formation",
        "context": "crystallizing along fractures or via the alteration of pre-existing inclusions",
        "priority": 2
    },
    {
        "entity": "Davemaoite (CaSiO3)",
        "behavior": "was discovered in its natural form",
        "context": "inside a diamond inclusion in 2021, previously only synthesized in laboratories",
        "priority": 2
    },
    {
        "entity": "Fluid inclusions",
        "behavior": "trap fluids containing silicates, carbonates, hydroxyl groups, water, and brine",
        "context": "primarily found in coated and fibrous diamonds",
        "priority": 1
    },
    {
        "entity": "Saline and silicic fluid inclusions",
        "behavior": "do not co-exist",
        "context": "implying the immiscibility of the two fluids during diamond formation",
        "priority": 2
    },
    {
        "entity": "Ice-VII",
        "behavior": "indicates the presence of water-rich fluids in the transition zone",
        "context": "inferred from its discovery as a high-pressure form of water in a diamond inclusion in 2018",
        "priority": 2
    },
    {
        "entity": "Multiphase inclusions",
        "behavior": "host fluids and mineral inclusions in the same diamond",
        "context": "originating from a single-phase supercritical mixture of hydrous silicate melt and aqueous fluid",
        "priority": 2
    },
    {
        "entity": "High-resolution techniques (FTIR, TEM, SEM, EPMA)",
        "behavior": "analyze the composition and phase of trapped material",
        "context": "commonly used research methods for studying diamond inclusions",
        "priority": 3
    },
    {
        "entity": "Non-destructive elastic methods",
        "behavior": "estimate pressure-temperature conditions while minimizing sample damage",
        "context": "using techniques like micro-Raman spectroscopy and single-crystal X-ray diffraction",
        "priority": 3
    }
]

[
    {
        "entity": "Double Asteroid Redirection Test (DART)",
        "behavior": "impacted the minor-planet moon Dimorphos reducing its orbital period by 32 minutes",
        "context": "conducted by NASA in 2022 as the world's first full-scale mission to test technology for asteroid deflection",
        "priority": 1
    },
    {
        "entity": "Kinetic impactor",
        "behavior": "alters the momentum of a celestial body by colliding a spacecraft with it at high velocity",
        "context": "considered the most mature non-nuclear approach for deflecting single small, solid bodies, as validated by the DART mission",
        "priority": 1
    },
    {
        "entity": "Nuclear explosive device",
        "behavior": "vaporizes surface material to create a rocket exhaust effect or disrupts the object depending on detonation method",
        "context": "acknowledged by NASA as potentially the only option for very large asteroids or threats identified with very short warning times",
        "priority": 1
    },
    {
        "entity": "China National Space Administration",
        "behavior": "plans to launch a deflection mission to the near-Earth object 2015 XF261",
        "context": "scheduled for launch in 2027 with the impact estimated to occur in April 2029",
        "priority": 2
    },
    {
        "entity": "Gravity tractor",
        "behavior": "uses a massive spacecraft hovering near an asteroid to gravitationally pull it into a different orbit",
        "context": "a slow-push mitigation technique that works irrespective of the asteroid's composition or spin rate",
        "priority": 2
    },
    {
        "entity": "NASA",
        "behavior": "requires at least five years of preparation to launch an interception mission",
        "context": "according to expert testimony given to the United States Congress in 2013 regarding current technological readiness",
        "priority": 2
    },
    {
        "entity": "U.S. Congress",
        "behavior": "mandated NASA to detect, track, and catalogue 90% of near-Earth objects equal to or greater than 140 meters",
        "context": "via the NASA Authorization Act of 2005, with a target completion within 15 years of enactment",
        "priority": 2
    },
    {
        "entity": "Asteroid Terrestrial-impact Last Alert System (ATLAS)",
        "behavior": "conducts nightly scans of the sky to detect asteroids on a collision stretch",
        "context": "providing warning times suitable for evacuation and preparation rather than deflection, operational since 2015",
        "priority": 2
    },
    {
        "entity": "Asteroid 2008 TC3",
        "behavior": "was identified in space before entering Earth's atmosphere allowing for accurate impact prediction",
        "context": "the first time scientists successfully predicted the arrival time and location (Nubian Desert) of an asteroid impact",
        "priority": 2
    },
    {
        "entity": "Carl Sagan",
        "behavior": "expressed concern that deflection technology could be abused to divert non-threatening bodies toward Earth",
        "context": "arguing in his book 'Pale Blue Dot' that the Earth might be at greater risk from man-made impacts than natural ones due to this technology",
        "priority": 3
    },
    {
        "entity": "International Asteroid Warning Network (IAWN)",
        "behavior": "acts as a clearinghouse for shared information on dangerous asteroids and future impact events",
        "context": "established following approval by the United Nations Committee on the Peaceful Uses of Outer Space in 2013",
        "priority": 3
    },
    {
        "entity": "Hypervelocity Asteroid Intercept Vehicle (HAIV)",
        "behavior": "combines a kinetic impactor to create a crater with a follow-up subsurface nuclear detonation",
        "context": "a concept proposed by Dr. Bong Wie to deal with objects 50-500 meters in diameter with less than one year to impact",
        "priority": 3
    },
    {
        "entity": "Ion beam deflection",
        "behavior": "uses a low-divergence ion thruster pointed at an asteroid to transmit momentum via ions",
        "context": "a 'contactless' technique similar to a gravity tractor but achievable with a lighter spacecraft",
        "priority": 3
    },
    {
        "entity": "Civilization defense strategies",
        "behavior": "fall into two primary sets: fragmentation and delay",
        "context": "fragmentation destroys the object while delay alters the orbit so the object and Earth do not arrive at the same point simultaneously",
        "priority": 1
    }
]

[
    {
        "entity": "Classic Maya collapse",
        "behavior": "involved the destabilization and abandonment of southern lowlands city-states",
        "context": "occurred between the 7th and 9th centuries CE",
        "priority": 1
    },
    {
        "entity": "Northern Yucatán",
        "behavior": "prospered and shifted to different artistic styles",
        "context": "following the collapse of the Southern Lowlands power centers",
        "priority": 2
    },
    {
        "entity": "Dated monuments",
        "behavior": "ceased construction",
        "context": "declined from forty per year around 750 to zero by 900, indicating societal decline",
        "priority": 2
    },
    {
        "entity": "Copán Valley population",
        "behavior": "declined steadily",
        "context": "fell from a peak of 28,000 (400-450 CE) to less than 1,000 (by 1200 CE) based on obsidian hydration dating",
        "priority": 2
    },
    {
        "entity": "Drought theory",
        "behavior": "posits that rapid climate change in the form of severe megadrought caused the collapse",
        "context": "has gained momentum as the leading explanation in the 21st century supported by scientific studies",
        "priority": 1
    },
    {
        "entity": "Annual precipitation",
        "behavior": "decreased between 41 and 54 percent",
        "context": "during the collapse period, based on analysis of water isotopes in gypsum crystals (Evans et al., 2018)",
        "priority": 1
    },
    {
        "entity": "Foreign invasion theory",
        "behavior": "suggests a non-Maya group from the gulf coast lowlands invaded",
        "context": "proposed to have set off destruction in the 9th century, though rejected by most Mayanists as the main cause",
        "priority": 2
    },
    {
        "entity": "Teotihuacán civilization",
        "behavior": "lost power and declined",
        "context": "during 600–650 CE, which is too early to directly precipitate the Late Classic Maya collapse",
        "priority": 2
    },
    {
        "entity": "Epidemic disease theory",
        "behavior": "suggests widespread infection caused rapid depopulation",
        "context": "potentially involving parasites and enteropathogens common in tropical rainforests",
        "priority": 2
    },
    {
        "entity": "Maya water management system",
        "behavior": "depended totally on consistent rainfall",
        "context": "making the civilization vulnerable to even slight shifts in precipitation in a seasonal desert environment",
        "priority": 2
    },
    {
        "entity": "Systemic ecological collapse",
        "behavior": "is evidenced by deforestation, siltation, and decline of biological diversity",
        "context": "resulting from resource exhaustion and agricultural stress",
        "priority": 1
    },
    {
        "entity": "Intensive agricultural methods",
        "behavior": "included canals, terracing, raised fields, and water reservoirs",
        "context": "utilized by the Maya to boost food production but dependent on ample water supplies",
        "priority": 2
    },
    {
        "entity": "Joseph Tainter",
        "behavior": "attributed the collapse to declining marginal returns",
        "context": "a result of the increasing social complexity of competing city-states",
        "priority": 2
    },
    {
        "entity": "Julian Jaynes",
        "behavior": "suggested a failure in social control systems",
        "context": "due to socioeconomic complexity overwhelming traditional rituals and kingly authority",
        "priority": 3
    },
    {
        "entity": "Gypsum",
        "behavior": "incorporates water molecules directly into its crystalline structure",
        "context": "allowing researchers to analyze fossil water isotopes to measure ancient drought severity",
        "priority": 3
    }
]

[
    {
        "entity": "Microplastics",
        "behavior": "are synthetic solid particles or polymeric matrices ranging from 1 μm to 5 mm",
        "context": "defined by their size, insolubility in water, and diverse manufacturing origins",
        "priority": 1
    },
    {
        "entity": "Primary microplastics",
        "behavior": "are purposefully manufactured to be small (5.0 mm or less)",
        "context": "entering the environment from sources like cosmetics (microbeads), air blasting media, and medicine",
        "priority": 2
    },
    {
        "entity": "Secondary microplastics",
        "behavior": "arise from the physical, biological, and photochemical degradation of larger plastic debris",
        "context": "occurring after larger plastics enter the environment and weather over time",
        "priority": 1
    },
    {
        "entity": "Nanoplastics",
        "behavior": "can cross cellular membranes and affect cell functioning due to their small size (<1 μm)",
        "context": "representing a significant risk to environmental and human health by accumulating in organs like the brain and pancreas",
        "priority": 1
